"use client";

import { useState, useEffect } from "react";
import { X, ChevronRight, ChevronLeft, CheckCircle, PlayCircle, BookOpen, Clock, ArrowRight } from "lucide-react";
import { type Lesson } from "@/lib/data";
import DiscussionSection from "./DiscussionSection";

interface LessonPlayerProps {
  courseTitle: string;
  lessons: Lesson[];
  currentLessonId: string;
  completedLessonIds: string[];
  onClose: () => void;
  onToggleComplete: (lessonId: string) => Promise<void>;
  onNavigate: (lessonId: string) => void;
}

export default function LessonPlayer({
  courseTitle,
  lessons,
  currentLessonId,
  completedLessonIds,
  onClose,
  onToggleComplete,
  onNavigate,
}: LessonPlayerProps) {
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    const found = lessons.find((l) => l.id === currentLessonId) || lessons[0];
    setActiveLesson(found);
  }, [currentLessonId, lessons]);

  if (!activeLesson) return null;

  const currentIndex = lessons.findIndex((l) => l.id === activeLesson.id);
  const nextLesson = lessons[currentIndex + 1];
  const prevLesson = lessons[currentIndex - 1];
  const isCompleted = completedLessonIds.includes(activeLesson.id);

  const handleToggleComplete = async () => {
    setIsSyncing(true);
    await onToggleComplete(activeLesson.id);
    setIsSyncing(false);
  };

  // Simple Markdown Parser for UI preview
  const parseContent = (content: string) => {
    return content
      .split("\n")
      .map((line, i) => {
        if (line.startsWith("###")) return <h3 key={i} className="text-xl font-bold text-white mt-6 mb-3">{line.replace("###", "").trim()}</h3>;
        if (line.startsWith("##")) return <h2 key={i} className="text-2xl font-bold text-white mt-8 mb-4">{line.replace("##", "").trim()}</h2>;
        if (line.startsWith("-")) return <li key={i} className="text-slate-400 ml-4 mb-2 list-disc">{line.replace("-", "").trim()}</li>;
        return <p key={i} className="text-slate-400 leading-relaxed mb-4">{line}</p>;
      });
  };

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col lg:flex-row animate-fade-in overflow-hidden">
      {/* Sidebar - Video & Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-y-auto custom-scrollbar">
        {/* Header Area */}
        <div className="h-16 border-b border-white/5 flex items-center justify-between px-6 bg-slate-900/50 backdrop-blur-md sticky top-0 z-20">
          <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors text-slate-400 hover:text-white">
              <X size={20} />
            </button>
            <div className="hidden sm:block">
              <p className="text-[10px] font-bold text-purple-400 uppercase tracking-widest">{courseTitle}</p>
