"use client";

import { useState, useEffect, useRef } from "react";
import { Bell, Trash2, CheckCircle2, AlertCircle, Info, ExternalLink } from "lucide-react";
import Link from "next/link";
import { useAuth } from "./AuthContext";
import { getUserNotifications, markAsRead, markAllAsRead, deleteNotification, type Notification } from "@/lib/notifications";

export default function NotificationBell() {
  const { user, isLoggedIn } = useAuth();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const unreadCount = notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    if (isLoggedIn && user) {
      fetchNotifications();
      // Polling for new notifications every 60 seconds
      const interval = setInterval(fetchNotifications, 60000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, user]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const fetchNotifications = async () => {
    if (!user) return;
    const data = await getUserNotifications(user.id);
    setNotifications(data);
  };

  const handleMarkAsRead = async (id: string) => {
    await markAsRead(id);
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const handleMarkAllAsRead = async () => {
    if (!user) return;
    await markAllAsRead(user.id);
    setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
  };

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    await deleteNotification(id);
    setNotifications(prev => prev.filter(n => n.id !== id));
  };

  if (!isLoggedIn) return null;

  return (
    <div className="relative" ref={dropdownRef}>
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="p-2 rounded-xl hover:bg-white/5 text-slate-400 hover:text-white transition-all relative"
        id="notification-bell"
      >
        <Bell size={20} />
        {unreadCount > 0 && (
          <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-red-500 text-white text-[10px] font-bold flex items-center justify-center rounded-full animate-pulse">
            {unreadCount > 9 ? '9+' : unreadCount}
          </span>
        )}
      </button>

      {isOpen && (
        <div className="absolute right-0 top-full mt-2 w-80 sm:w-96 glass-strong rounded-2xl overflow-hidden shadow-2xl z-[60] animate-fade-in border border-white/10">
          <div className="p-4 border-b border-white/10 flex items-center justify-between bg-white/5">
            <h3 className="text-sm font-semibold text-white">Notifikasi</h3>
            {unreadCount > 0 && (
              <button
                onClick={handleMarkAllAsRead}
                className="text-[11px] text-cyan-400 hover:text-cyan-300 font-medium"
              >
                Tandai semua dibaca
              </button>
            )}
          </div>

          <div className="max-h-[400px] overflow-y-auto custom-scrollbar">
            {notifications.length === 0 ? (
              <div className="p-8 text-center">
                <div className="w-12 h-12 rounded-full bg-white/5 flex items-center justify-center mx-auto mb-3">
                  <Bell size={20} className="text-slate-600" />
                </div>
                <p className="text-sm text-slate-500">Belum ada notifikasi.</p>
              </div>
            ) : (
              notifications.map((n) => (
                <div
                  key={n.id}
                  onClick={() => handleMarkAsRead(n.id)}
                  className={`p-4 border-b border-white/5 hover:bg-white/[0.03] transition-colors cursor-pointer relative group ${!n.isRead ? 'bg-cyan-500/[0.02]' : ''}`}
                >
                  <div className="flex gap-3">
                    <div className={`mt-1 flex-shrink-0 w-8 h-8 rounded-lg flex items-center justify-center ${
                      n.type === 'success' ? 'bg-emerald-500/10 text-emerald-400' :
                      n.type === 'warning' ? 'bg-amber-500/10 text-amber-400' :
                      n.type === 'error' ? 'bg-red-500/10 text-red-400' :
                      'bg-blue-500/10 text-blue-400'
                    }`}>
                      {n.type === 'success' ? <CheckCircle2 size={16} /> :
                       n.type === 'warning' ? <AlertCircle size={16} /> :
                       n.type === 'error' ? <AlertCircle size={16} /> :
                       <Info size={16} />}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between gap-2 mb-1">
                        <p className={`text-sm font-medium truncate ${!n.isRead ? 'text-white' : 'text-slate-300'}`}>
                          {n.title}
                        </p>
                        <span className="text-[10px] text-slate-500 whitespace-nowrap">
                          {new Date(n.createdAt).toLocaleDateString()}
                        </span>
                      </div>
                      <p className="text-xs text-slate-400 line-clamp-2 leading-relaxed">
                        {n.message}
                      </p>
                      {n.linkUrl && (
                        <Link 
                          href={n.linkUrl}
                          className="inline-flex items-center gap-1 mt-2 text-[10px] text-cyan-400 hover:text-cyan-300 font-medium"
                          onClick={() => setIsOpen(false)}
                        >
                          Lihat detail <ExternalLink size={10} />
                        </Link>
                      )}
                    </div>
                  </div>
                  <button
                    onClick={(e) => handleDelete(e, n.id)}
                    className="absolute right-2 bottom-2 p-1.5 text-slate-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all"
                    title="Hapus"
                  >
                    <Trash2 size={12} />
                  </button>
                  {!n.isRead && (
                    <div className="absolute left-1.5 top-1/2 -translate-y-1/2 w-1 h-8 bg-cyan-500 rounded-full" />
                  )}
                </div>
              ))
            )}
          </div>

          <div className="p-3 text-center bg-white/5 border-t border-white/10">
            <Link 
              href="/dashboard/notifications" 
              className="text-xs text-slate-400 hover:text-white transition-colors"
              onClick={() => setIsOpen(false)}
            >
              Lihat semua notifikasi
            </Link>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useRef } from "react";
import { X, Upload, CheckCircle2, AlertCircle, Loader2, QrCode, ArrowRight } from "lucide-react";
import Image from "next/image";
import { Enrollment, uploadPaymentProof } from "@/lib/enrollment";

interface PaymentModalProps {
  enrollment: Enrollment;
  qrisUrl: string;
  courseTitle: string;
  onClose: () => void;
  onSuccess: () => void;
}

export default function PaymentModal({ enrollment, qrisUrl, courseTitle, onClose, onSuccess }: PaymentModalProps) {
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      if (selectedFile.size > 2 * 1024 * 1024) {
        setError("Ukuran file maksimal adalah 2MB");
        return;
      }
      setFile(selectedFile);
      setError(null);

      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleUpload = async () => {
    if (!file || !preview) {
      setError("Silakan pilih bukti pembayaran terlebih dahulu.");
      return;
    }

    setIsUploading(true);
    setError(null);

    // Simulate Supabase Storage Upload
    const result = await uploadPaymentProof(enrollment.id, preview);
    setIsUploading(false);

    if (result.success) {
      onSuccess();
    } else {
      setError(result.error || "Gagal mengunggah bukti.");
    }
  };

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center bg-black/95 backdrop-blur-md p-4 animate-in fade-in duration-300">
      <div className="bg-[#0f0f1a] rounded-2xl border border-white/10 max-w-2xl w-full max-h-[95vh] overflow-hidden flex flex-col shadow-2xl scale-in-center">
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-white/5 bg-white/5">
          <div>
            <span className="text-[10px] font-bold text-cyan-400 uppercase tracking-widest mb-1 block">Konfirmasi Pembayaran</span>
            <h2 className="text-white font-bold text-lg leading-tight">{courseTitle}</h2>
          </div>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-white hover:bg-white/5 rounded-lg transition-all">
            <X size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-auto p-6 md:p-8">
          <div className="grid md:grid-cols-2 gap-8">
            {/* Left: QRIS Info */}
            <div className="space-y-6">
              <div className="text-center md:text-left">
                <h3 className="text-white font-bold mb-2 flex items-center gap-2">
                  <QrCode size={18} className="text-purple-400" />
                  Scan QRIS di Bawah
                </h3>
                <p className="text-slate-400 text-xs leading-relaxed">
                  Silakan lakukan pembayaran sesuai harga kursus. Pastikan nominal sesuai agar verifikasi lebih cepat.
                </p>
              </div>

              <div className="bg-white p-4 rounded-xl flex items-center justify-center shadow-lg shadow-purple-500/10">
                <Image 
                  src={qrisUrl || "https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=MyLearning-Mock"} 
                  alt="QRIS Payment" 
                  width={250} 
                  height={250} 
                  className="rounded-lg"
                />
              </div>

              <div className="card !bg-purple-500/5 p-4 border-purple-500/20">
                <div className="flex gap-3">
                  <AlertCircle size={16} className="text-purple-400 shrink-0 mt-0.5" />
                  <p className="text-[11px] text-slate-300 leading-relaxed">
                    Kesempatan mengunggah bukti: <span className="text-white font-bold">{3 - enrollment.paymentRetryCount} kali lagi</span>.
                    Jika gagal 3x, pendaftaran akan dibatalkan otomatis.
                  </p>
                </div>
              </div>
            </div>

            {/* Right: Upload Section */}
            <div className="flex flex-col">
              <h3 className="text-white font-bold mb-4 flex items-center gap-2">
                <Upload size={18} className="text-cyan-400" />
                Upload Bukti Bayar
              </h3>

              <div 
                onClick={() => fileInputRef.current?.click()}
                className={`flex-1 min-h-[200px] border-2 border-dashed rounded-2xl flex flex-col items-center justify-center p-6 transition-all cursor-pointer group ${
                  preview ? "border-cyan-500/50 bg-cyan-500/5" : "border-white/10 hover:border-white/20 hover:bg-white/5"
                }`}
              >
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handleFileChange} 
                  accept="image/*" 
                  className="hidden" 
                />

                {preview ? (
                  <div className="relative w-full h-full flex flex-col items-center">
                    <div className="relative w-full aspect-[3/4] mb-4">
                      <Image 
                        src={preview} 
                        alt="Preview" 
                        fill 
                        className="object-contain rounded-lg"
                      />
                    </div>
                    <p className="text-slate-400 text-xs">Klik untuk ganti gambar</p>
                  </div>
                ) : (
                  <>
                    <div className="w-12 h-12 rounded-full bg-white/5 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                      <Upload size={24} className="text-slate-500 group-hover:text-cyan-400" />
                    </div>
                    <p className="text-white text-sm font-medium mb-1">Klik atau seret file</p>
                    <p className="text-slate-500 text-xs">JPG, PNG (Maks 2MB)</p>
                  </>
                )}
              </div>

              {error && (
                <div className="mt-4 p-3 rounded-lg bg-red-500/10 border border-red-500/20 flex items-center gap-2 text-red-400 text-xs">
                  <AlertCircle size={14} />
                  {error}
                </div>
              )}

              <button
                onClick={handleUpload}
                disabled={!file || isUploading}
                className={`btn-primary w-full mt-6 flex items-center justify-center gap-2 !py-4 font-bold shadow-xl shadow-purple-500/20 disabled:opacity-50 disabled:cursor-not-allowed`}
              >
                {isUploading ? (
                  <>
                    <Loader2 size={18} className="animate-spin" /> Mengunggah...
                  </>
                ) : (
                  <>
                    Kirim Bukti Pembayaran <ArrowRight size={18} />
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { X, ArrowRight, ArrowLeft, CheckCircle, XCircle, RotateCcw, Award } from "lucide-react";
import type { Quiz } from "@/lib/assessments";

interface QuizModalProps {
  quiz: Quiz;
  enrollmentId: string;
  alreadyPassed: boolean;
  previousScore?: number;
  onSubmit: (quizId: string | number, answers: number[]) => Promise<{ score: number; passed: boolean }>;
  onClose: () => void;
}

export default function QuizModal({ quiz, enrollmentId, alreadyPassed, previousScore, onSubmit, onClose }: QuizModalProps) {
  const [currentQ, setCurrentQ] = useState(0);
  const [answers, setAnswers] = useState<number[]>(new Array(quiz.questions.length).fill(-1));
  const [submitted, setSubmitted] = useState(false);
  const [score, setScore] = useState(0);
  const [passed, setPassed] = useState(false);

  const question = quiz.questions[currentQ];
  const allAnswered = answers.every((a) => a !== -1);

  const handleSelect = (optionIdx: number) => {
    if (submitted) return;
    const newAnswers = [...answers];
    newAnswers[currentQ] = optionIdx;
    setAnswers(newAnswers);
  };

  const handleSubmit = async () => {
    const result = await onSubmit(quiz.id, answers);
    setScore(result.score);
    setPassed(result.passed);
    setSubmitted(true);
  };

  const handleRetry = () => {
    setAnswers(new Array(quiz.questions.length).fill(-1));
    setSubmitted(false);
    setCurrentQ(0);
    setScore(0);
    setPassed(false);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-[#0c0c14] rounded-2xl border border-white/10 max-w-2xl w-full max-h-[90vh] overflow-auto shadow-2xl">
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-white/5">
          <div>
            <h2 className="text-lg font-bold text-white">{quiz.title}</h2>
            <p className="text-xs text-slate-500">Skor minimal: {quiz.passingScore}%</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors"><X size={20} /></button>
        </div>

        {!submitted ? (
          <>
            {/* Progress */}
            <div className="px-6 pt-4">
              <div className="flex items-center justify-between text-xs text-slate-500 mb-2">
                <span>Pertanyaan {currentQ + 1} / {quiz.questions.length}</span>
                <span>{answers.filter((a) => a !== -1).length} dijawab</span>
              </div>
              <div className="h-1.5 rounded-full bg-white/5 overflow-hidden">
                <div className="h-full bg-gradient-to-r from-purple-500 to-cyan-400 rounded-full transition-all" style={{ width: `${((currentQ + 1) / quiz.questions.length) * 100}%` }} />
              </div>
            </div>

            {/* Question */}
            <div className="p-6">
              <h3 className="text-white font-semibold mb-6">{question.question}</h3>
              <div className="space-y-3">
                {question.options.map((opt, i) => (
                  <button
                    key={i}
                    onClick={() => handleSelect(i)}
                    className={`w-full text-left p-4 rounded-xl border transition-all ${
                      answers[currentQ] === i
                        ? "border-purple-500/50 bg-purple-500/10 text-white"
                        : "border-white/5 bg-white/[0.02] text-slate-300 hover:border-white/20 hover:bg-white/5"
                    }`}
                  >
                    <div className="flex items-center gap-3">
                      <div className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0 ${
                        answers[currentQ] === i ? "bg-purple-500 text-white" : "bg-white/5 text-slate-500"
                      }`}>
                        {String.fromCharCode(65 + i)}
                      </div>
                      <span className="text-sm">{opt}</span>
                    </div>
                  </button>
                ))}
              </div>
            </div>

            {/* Navigation */}
            <div className="flex items-center justify-between px-6 pb-6">
              <button
                onClick={() => setCurrentQ((c) => Math.max(0, c - 1))}
                disabled={currentQ === 0}
                className="flex items-center gap-1.5 text-sm text-slate-400 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
              >
                <ArrowLeft size={16} /> Sebelumnya
              </button>

              {currentQ < quiz.questions.length - 1 ? (
                <button
                  onClick={() => setCurrentQ((c) => c + 1)}
                  className="flex items-center gap-1.5 text-sm text-purple-400 hover:text-purple-300 transition-colors"
                >
                  Selanjutnya <ArrowRight size={16} />
                </button>
              ) : (
                <button
                  onClick={handleSubmit}
                  disabled={!allAnswered}
                  className="btn-primary text-sm !py-2 !px-5 disabled:opacity-30 disabled:cursor-not-allowed"
                >
                  Submit Quiz
                </button>
              )}
            </div>

            {/* Question dots */}
            <div className="flex items-center justify-center gap-2 px-6 pb-4">
              {quiz.questions.map((_, i) => (
                <button
                  key={i}
                  onClick={() => setCurrentQ(i)}
                  className={`w-8 h-8 rounded-lg text-xs font-medium transition-all ${
                    i === currentQ ? "bg-purple-500 text-white" : answers[i] !== -1 ? "bg-emerald-500/20 text-emerald-400" : "bg-white/5 text-slate-600"
                  }`}
                >
                  {i + 1}
                </button>
              ))}
            </div>
          </>
        ) : (
          /* Results */
          <div className="p-6 text-center">
            <div className={`w-20 h-20 rounded-full mx-auto mb-4 flex items-center justify-center ${passed ? "bg-emerald-500/15" : "bg-red-500/15"}`}>
              {passed ? <Award size={36} className="text-emerald-400" /> : <XCircle size={36} className="text-red-400" />}
            </div>
            <h3 className="text-2xl font-bold text-white mb-2">
              {passed ? "Selamat! Quiz Lulus! ≡ƒÄë" : "Belum Lulus ≡ƒÿö"}
            </h3>
            <p className="text-4xl font-extrabold gradient-text mb-2">{score}%</p>
            <p className="text-slate-400 text-sm mb-6">Skor minimal: {quiz.passingScore}%</p>

            {/* Answer Review */}
            <div className="text-left space-y-4 mb-6 max-h-[300px] overflow-auto">
              {quiz.questions.map((q, i) => {
                const isCorrect = answers[i] === q.correctAnswer;
                return (
                  <div key={q.id} className={`p-4 rounded-xl border ${isCorrect ? "border-emerald-500/20 bg-emerald-500/5" : "border-red-500/20 bg-red-500/5"}`}>
                    <div className="flex items-start gap-2 mb-2">
                      {isCorrect ? <CheckCircle size={16} className="text-emerald-400 mt-0.5" /> : <XCircle size={16} className="text-red-400 mt-0.5" />}
                      <p className="text-sm text-white">{q.question}</p>
                    </div>
                    <p className="text-xs text-slate-500 ml-6">
                      Jawaban Anda: <span className={isCorrect ? "text-emerald-400" : "text-red-400"}>{q.options[answers[i]] || "-"}</span>
                    </p>
                    {!isCorrect && <p className="text-xs text-slate-500 ml-6">Jawaban benar: <span className="text-emerald-400">{q.options[q.correctAnswer]}</span></p>}
                    {q.explanation && <p className="text-xs text-slate-400 ml-6 mt-1 italic">{q.explanation}</p>}
                  </div>
                );
              })}
            </div>

            <div className="flex items-center justify-center gap-3">
              {!passed && (
                <button onClick={handleRetry} className="btn-primary text-sm !py-2.5 flex items-center gap-2">
                  <RotateCcw size={16} /> Coba Lagi
                </button>
              )}
              <button onClick={onClose} className="btn-secondary text-sm !py-2.5">Tutup</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { Star, MessageSquare, AlertCircle, CheckCircle2, User, Send } from "lucide-react";
import { Review, getCourseReviews, addReview } from "@/lib/reviews";
import { useAuth } from "@/app/components/AuthContext";
import { getUserEnrollments } from "@/lib/enrollment";

interface ReviewSectionProps {
  courseSlug: string;
  courseTitle: string;
}

export default function ReviewSection({ courseSlug, courseTitle }: ReviewSectionProps) {
  const { user, isLoggedIn } = useAuth();
  const [reviews, setReviews] = useState<Review[]>([]);
  const [canReview, setCanReview] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState("");
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    // Load reviews
    getCourseReviews(courseSlug).then(setReviews);

    // Check if user has completed this course
    if (user) {
      getUserEnrollments(user.id).then((enrollments) => {
        const isCompleted = enrollments.some(
          (e) => e.courseSlug === courseSlug && e.status === "completed"
        );
        setCanReview(isCompleted);
      });
    }
  }, [courseSlug, user]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;

    const result = await addReview({
      courseSlug,
      userId: user.id,
      userName: user.fullName,
      rating,
      comment,
    });

    if (result.success) {
      setSubmitted(true);
      const updatedReviews = await getCourseReviews(courseSlug);
      setReviews(updatedReviews);
      setShowForm(false);
    }
  };

  return (
    <div className="mt-16 border-t border-white/5 pt-12">
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6 mb-10">
        <div>
          <h2 className="text-2xl font-bold text-white mb-2">Ulasan Siswa</h2>
          <p className="text-slate-400 text-sm">Apa kata mereka yang telah menyelesaikan kursus ini?</p>
        </div>

        {isLoggedIn && canReview && !submitted && (
          <button 
            onClick={() => setShowForm(!showForm)}
            className="btn-primary flex items-center gap-2 !py-2 !px-4 text-sm"
          >
            <Star size={16} /> {showForm ? "Batal Menilai" : "Berikan Penilaian"}
          </button>
        )}
      </div>

      {/* Review Submission Form */}
      {showForm && (
        <div className="card p-6 mb-10 border border-purple-500/20 bg-purple-500/5 animate-in slide-in-from-top duration-300">
          <h3 className="text-white font-bold mb-4 flex items-center gap-2">
            <CheckCircle2 size={18} className="text-emerald-400" />
            Terima kasih telah menyelesaikan kursus! Bagaimana pengalaman Anda?
          </h3>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-xs text-slate-400 mb-2 uppercase tracking-wider font-bold">Rating Anda</label>
              <div className="flex gap-2">
                {[1, 2, 3, 4, 5].map((star) => (
                  <button
                    key={star}
                    type="button"
                    onClick={() => setRating(star)}
                    className={`p-2 transition-all ${rating >= star ? "text-yellow-400" : "text-slate-600 hover:text-slate-400"}`}
                  >
                    <Star size={24} fill={rating >= star ? "currentColor" : "none"} />
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="block text-xs text-slate-400 mb-2 uppercase tracking-wider font-bold">Komentar / Masukan</label>
              <textarea
                value={comment}
                onChange={(e) => setComment(e.target.value)}
                placeholder="Tuliskan pengalaman belajar Anda di sini..."
                className="input-field min-h-[100px] resize-none"
                required
              />
            </div>
            <button type="submit" className="btn-primary w-full flex items-center justify-center gap-2">
              <Send size={18} /> Kirim Ulasan
            </button>
          </form>
        </div>
      )}

      {submitted && (
        <div className="card p-4 mb-10 border border-emerald-500/20 bg-emerald-500/5 text-emerald-400 text-sm flex items-center gap-3">
          <CheckCircle2 size={20} /> Ulasan Anda telah berhasil dikirim! Terima kasih atas partisipasinya.
        </div>
      )}

      {!isLoggedIn && (
        <div className="card p-4 mb-10 border border-white/5 bg-white/5 text-slate-400 text-sm flex items-center gap-3">
          <AlertCircle size={20} /> Silakan login untuk melihat status penilaian Anda.
        </div>
      )}

      {isLoggedIn && !canReview && !submitted && (
        <div className="card p-4 mb-10 border border-blue-500/20 bg-blue-500/5 text-blue-400 text-sm flex items-center gap-3">
          <AlertCircle size={20} /> Hanya siswa yang telah **menyelesaikan kursus (100% progress)** yang dapat memberikan ulasan.
        </div>
      )}

      {/* Reviews List */}
      <div className="grid md:grid-cols-2 gap-6">
        {reviews.length > 0 ? (
          reviews.map((review) => (
            <div key={review.id} className="card p-6 border border-white/5 hover:border-white/10 transition-colors">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center text-slate-400">
                    <User size={20} />
                  </div>
                  <div>
                    <Link href={`/profile/${review.userId}`} className="text-white font-bold text-sm hover:text-purple-400 transition-colors">{review.userName}</Link>
                    <p className="text-[10px] text-slate-500">{new Date(review.createdAt).toLocaleDateString("id-ID", { day: "numeric", month: "long", year: "numeric" })}</p>
                  </div>
                </div>
                <div className="flex gap-0.5">
                  {[...Array(5)].map((_, i) => (
                    <Star 
                      key={i} 
                      size={12} 
                      className={i < review.rating ? "text-yellow-400 fill-yellow-400" : "text-slate-700"} 
                    />
                  ))}
                </div>
              </div>
              <p className="text-slate-400 text-sm italic leading-relaxed">
                &quot;{review.comment}&quot;
              </p>
            </div>
          ))
        ) : (
          <div className="col-span-2 py-12 text-center card border-dashed border-white/10">
            <MessageSquare size={40} className="text-slate-700 mx-auto mb-4" />
            <p className="text-slate-500 text-sm italic">Belum ada ulasan untuk kursus ini. Jadilah yang pertama memberikan ulasan!</p>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { 
  ArrowLeft, Save, Loader2, Plus, Trash2, CheckCircle, AlertCircle, 
  Image as ImageIcon, Play, FileText, ChevronUp, ChevronDown, Edit, X, Eye,
  Brain, Target, Upload, Info, BookOpen, Clock
} from "lucide-react";
import { 
  getCategories, getInstructors, upsertCourse, getAdminCourseById, 
  upsertLesson, deleteLesson, updateLessonsOrder 
} from "@/lib/courses";
import { 
  getCourseAssessments, upsertAssessment, deleteAssessment, 
  upsertQuizQuestion, deleteQuizQuestion 
} from "@/lib/assessments";
import { uploadThumbnail } from "@/lib/storage";
import { supabase } from "@/lib/supabase";
import { type Course } from "@/lib/data";
import Link from "next/link";
import Skeleton from "../ui/Skeleton";
import VideoInput from "../VideoInput";

interface Props {
  courseId?: string;
}

interface CourseFormData {
  id?: string;
  title: string;
  slug: string;
  description: string;
  detailedDescription: string;
  thumbnail: string;
  price: number;
  discountPrice: number;
  categoryId: string;
  instructorIdDb: string;
  level: "Starter" | "Accelerator" | "Mastery";
  language: string;
  durationHours: number;
  totalLessons: number;
  isPublished: boolean;
  isFeatured: boolean;
  learningPoints: string[];
  requirements: string[];
  lessons: any[];
}

interface NotificationState {
  show: boolean;
  message: string;
  type: "success" | "error";
}

export default function CourseForm({ courseId }: Props) {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(!!courseId);
  const [categories, setCategories] = useState<{id: string, name: string}[]>([]);
  const [instructors, setInstructors] = useState<{id: string, name: string}[]>([]);
  const [notification, setNotification] = useState<NotificationState>({ show: false, message: "", type: "success" });
  const [activeTab, setActiveTab] = useState<"basic" | "curriculum" | "assessments">("basic");
  const [isUploading, setIsUploading] = useState(false);

  // Assessments state
  const [assessments, setAssessments] = useState<any>({ quizzes: [], assignments: [], finalProject: null });
  const [assessmentModal, setAssessmentModal] = useState<{
    isOpen: boolean;
    type: "quiz" | "assignment" | "final_project";
    data: any | null;
    isSaving: boolean;
  }>({
    isOpen: false,
    type: "quiz",
    data: null,
    isSaving: false
  });

  const [questionModal, setQuestionModal] = useState<{
    isOpen: boolean;
    assessmentId: string;
    data: any | null;
    isSaving: boolean;
  }>({
    isOpen: false,
    assessmentId: "",
    data: null,
    isSaving: false
  });

  const [formData, setFormData] = useState<CourseFormData>({
    title: "",
    slug: "",
    description: "",
    detailedDescription: "",
    thumbnail: "",
    price: 0,
    discountPrice: 0,
    categoryId: "",
    instructorIdDb: "",
    level: "Starter",
    language: "Bahasa Indonesia",
    durationHours: 1,
    totalLessons: 0,
    isPublished: false,
    isFeatured: false,
    learningPoints: [""],
    requirements: [""],
    lessons: []
  });

  const [lessonModal, setLessonModal] = useState<{
    isOpen: boolean;
    lesson: any | null;
    isSaving: boolean;
  }>({
    isOpen: false,
    lesson: null,
    isSaving: false
  });

  const [isReordering, setIsReordering] = useState(false);

  useEffect(() => {
    async function loadResources() {
      setFetching(true);
      try {
        const [cats, insts] = await Promise.all([getCategories(), getInstructors()]);

        setCategories(cats.map(c => ({ id: (c as any).id || c.slug, name: c.name })) || []);
        setInstructors(insts.map(i => ({ id: (i as any).id || i.id, name: i.name })) || []);

        if (courseId) {
          const course = await getAdminCourseById(courseId);
          if (course) {
            setFormData({
              id: course.id,
              title: course.title,
              slug: course.slug,
              description: course.short_description || "",
              detailedDescription: course.description || "",
              thumbnail: course.thumbnail_url || "",
              price: course.price || 0,
              discountPrice: course.discount_price || 0,
              categoryId: course.category_id,
              instructorIdDb: course.instructor_id,
              level: course.level,
              language: course.language || "Bahasa Indonesia",
              durationHours: Number(course.duration_hours) || 0,
              totalLessons: course.total_lessons || 0,
              isPublished: !!course.is_published,
              isFeatured: !!course.is_featured,
              learningPoints: course.learning_points || [""],
              requirements: course.requirements || [""],
              lessons: course.lessons || []
            });

            const realAssessments = await getCourseAssessments(course.slug);
            if (realAssessments) setAssessments(realAssessments);
          }
        }
      } catch (err) {
        console.error("Error loading resources:", err);
      } finally {
        setFetching(false);
      }
    }
    loadResources();
  }, [courseId]);

  const showNotification = (message: string, type: "success" | "error") => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 4000);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const res = await upsertCourse(formData as any);
    setLoading(false);

    if (res.success) {
      showNotification("Data kursus berhasil disimpan!", "success");
      setTimeout(() => router.push("/dashboard/admin/courses"), 1500);
    } else {
      showNotification("Gagal menyimpan: " + (res.error as any).message, "error");
    }
  };

  const handleArrayChange = (field: 'learningPoints' | 'requirements', index: number, value: string) => {
    const newArr = [...formData[field]];
    newArr[index] = value;
    setFormData({ ...formData, [field]: newArr });
  };

  const addArrayItem = (field: 'learningPoints' | 'requirements') => {
    setFormData({ ...formData, [field]: [...formData[field], ""] });
  };

  const removeArrayItem = (field: 'learningPoints' | 'requirements', index: number) => {
    const newArr = formData[field].filter((_: any, i: number) => i !== index);
    setFormData({ ...formData, [field]: newArr });
  };

  // Lesson Handlers
  const openLessonModal = (lesson: any = null) => {
    setLessonModal({
      isOpen: true,
      lesson: lesson || {
        course_id: courseId,
        title: "",
        duration_minutes: 0,
        video_url: "",
        description: "",
        is_free_preview: false,
        content_type: "video",
        order_index: formData.lessons.length
      },
      isSaving: false
    });
  };

  const handleSaveLesson = async (lessonData: any) => {
    if (!courseId) {
        showNotification("Simpan kursus terlebih dahulu sebelum mengelola materi.", "error");
        return;
    }

    setLessonModal(prev => ({ ...prev, isSaving: true }));
    const res = await upsertLesson({ ...lessonData, course_id: courseId });
    setLessonModal(prev => ({ ...prev, isSaving: false }));

    if (res.success) {
      showNotification("Materi berhasil disimpan!", "success");
      setLessonModal({ isOpen: false, lesson: null, isSaving: false });

      const course = await getAdminCourseById(courseId as string);
      if (course) {
        setFormData(prev => ({ ...prev, lessons: course.lessons || [] }));
      }
    } else {
      showNotification("Gagal menyimpan materi: " + (res.error as any).message, "error");
    }
  };

  const handleDeleteLesson = async (id: string, title: string) => {
    if (!confirm(`Hapus materi "${title}"?`)) return;

    const res = await deleteLesson(id);
    if (res.success) {
      showNotification("Materi berhasil dihapus.", "success");
      setFormData(prev => ({ 
        ...prev, 
        lessons: prev.lessons.filter(l => l.id !== id) 
      }));
    } else {
      showNotification("Gagal menghapus: " + (res.error as any).message, "error");
    }
  };

  // Thumbnail Upload Handler
  const handleThumbnailUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    const { url, error } = await uploadThumbnail(file);
    setIsUploading(false);

    if (error) {
      showNotification("Gagal mengunggah gambar: " + error.message, "error");
    } else if (url) {
      setFormData({ ...formData, thumbnail: url });
      showNotification("Gambar berhasil diunggah!", "success");
    }
  };

  // Assessment Handlers
  const handleSaveAssessment = async (data: any) => {
    if (!courseId) return;
    setAssessmentModal(prev => ({ ...prev, isSaving: true }));
    const res = await upsertAssessment({ ...data, course_id: courseId });
    setAssessmentModal(prev => ({ ...prev, isSaving: false }));

    if (res.success) {
      showNotification("Asesmen berhasil disimpan!", "success");
      setAssessmentModal({ isOpen: false, type: "quiz", data: null, isSaving: false });
      const updated = await getCourseAssessments(formData.slug);
      if (updated) setAssessments(updated);
    } else {
      showNotification("Gagal menyimpan: " + (res.error as any).message, "error");
    }
  };

  const handleDeleteAssessment = async (id: string, title: string) => {
    if (!confirm(`Hapus asesmen "${title}"?`)) return;
    const res = await deleteAssessment(id);
    if (res.success) {
      showNotification("Asesmen berhasil dihapus.", "success");
      const updated = await getCourseAssessments(formData.slug);
      if (updated) setAssessments(updated);
    }
  };

  const handleSaveQuestion = async (data: any) => {
    setQuestionModal(prev => ({ ...prev, isSaving: true }));
    const res = await upsertQuizQuestion(data);
    setQuestionModal(prev => ({ ...prev, isSaving: false }));

    if (res.success) {
      showNotification("Pertanyaan berhasil disimpan!", "success");
      setQuestionModal({ isOpen: false, assessmentId: "", data: null, isSaving: false });
      const updated = await getCourseAssessments(formData.slug);
      if (updated) setAssessments(updated);
    }
  };

  const handleDeleteQuestion = async (id: string) => {
    if (!confirm("Hapus pertanyaan ini?")) return;
    const res = await deleteQuizQuestion(id);
    if (res.success) {
      const updated = await getCourseAssessments(formData.slug);
      if (updated) setAssessments(updated);
    }
  };

  const handleMoveLesson = async (index: number, direction: 'up' | 'down') => {
    if (isReordering) return;
    const newLessons = [...formData.lessons];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newLessons.length) return;
    [newLessons[index], newLessons[targetIndex]] = [newLessons[targetIndex], newLessons[index]];
    const updatedLessons = newLessons.map((l, i) => ({ id: l.id, order_index: i }));
    setFormData(prev => ({ ...prev, lessons: newLessons }));
    setIsReordering(true);
    const res = await updateLessonsOrder(updatedLessons);
    setIsReordering(false);
    if (!res.success) {
      showNotification("Gagal memperbarui urutan materi.", "error");
      const course = await getAdminCourseById(courseId as string);
      if (course) setFormData(prev => ({ ...prev, lessons: course.lessons || [] }));
    }
  };

  if (fetching) {
    return (
      <div className="max-w-4xl mx-auto space-y-8 pb-20 animate-fade-in">
        <Skeleton className="h-10 w-full rounded-xl" />
        <div className="grid md:grid-cols-2 gap-6">
          <Skeleton className="h-64 rounded-2xl" />
          <Skeleton className="h-64 rounded-2xl" />
        </div>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="max-w-4xl mx-auto space-y-8 pb-20 animate-fade-in">
      {notification.show && (
        <div className={`fixed top-6 right-6 z-50 flex items-center gap-3 px-6 py-4 rounded-2xl border shadow-2xl glass-strong animate-slide-right ${
          notification.type === "success" ? "border-emerald-500/30 text-emerald-400" : "border-red-500/30 text-red-400"
        }`}>
          {notification.type === "success" ? <CheckCircle size={20} /> : <AlertCircle size={20} />}
          <p className="font-semibold">{notification.message}</p>
        </div>
      )}

      {/* Header & Tab Switcher */}
      <div className="flex items-center justify-between sticky top-0 z-10 py-4 glass bg-background/80 -mx-4 px-4 rounded-2xl mb-4 backdrop-blur-xl transition-all duration-300">
        <div className="flex items-center gap-3">
          <Link href="/dashboard/admin/courses" className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center hover:bg-white/10 transition-colors group">
            <ArrowLeft size={20} className="text-white transition-transform group-hover:-translate-x-1" />
          </Link>
          <h1 className="text-2xl font-bold text-white tracking-tight">
            {courseId ? "Simulasi" : "Tambah"} <span className="gradient-text">Kursus</span>
          </h1>
        </div>
        <div className="flex items-center gap-4">
           <div className="hidden md:flex items-center bg-white/5 p-1 rounded-xl border border-white/5">
              {[
                { id: 'basic', label: 'Dashboard', icon: Edit },
                { id: 'curriculum', label: 'Kurikulum', icon: BookOpen },
                { id: 'assessments', label: 'Asesmen', icon: Brain },
              ].map(t => (
                <button
                  key={t.id}
                  type="button"
                  onClick={() => setActiveTab(t.id as any)}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${
                    activeTab === t.id ? 'bg-purple-500 text-white shadow-lg shadow-purple-500/20' : 'text-slate-500 hover:text-white'
                  }`}
                >
                  <t.icon size={14} /> {t.label}
                </button>
              ))}
           </div>
           <button type="submit" disabled={loading} className="btn-primary flex items-center gap-2 px-8 min-w-[140px]">
             {loading ? <Loader2 className="animate-spin" size={20} /> : <Save size={20} />}
             <span className="font-bold">{courseId ? "Perbarui" : "Simpan"}</span>
           </button>
        </div>
      </div>

      {activeTab === "basic" && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
           <div className="grid md:grid-cols-2 gap-6">
              {/* Basic Info Card */}
              <div className="card p-8 space-y-6">
                 <h2 className="text-lg font-bold text-white flex items-center gap-2">Informasi Dasar</h2>
                 <div className="space-y-4">
                    <input className="input w-full" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} placeholder="Judul Kursus" required />
                    <input className="input w-full" value={formData.slug} onChange={e => setFormData({...formData, slug: e.target.value})} placeholder="Slug Kursus" required />
                    <select className="input w-full" value={formData.categoryId} onChange={e => setFormData({...formData, categoryId: e.target.value})} required>
                       <option value="">Pilih Kategori</option>
                       {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </select>
                    <select className="input w-full" value={formData.instructorIdDb} onChange={e => setFormData({...formData, instructorIdDb: e.target.value})} required>
                       <option value="">Pilih Instruktur</option>
                       {instructors.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
                    </select>
                 </div>
              </div>

              {/* Pricing Card */}
              <div className="card p-8 space-y-6">
                 <h2 className="text-lg font-bold text-white">Harga & Level</h2>
                 <div className="space-y-4">
                    <input type="number" className="input w-full" value={formData.price} onChange={e => setFormData({...formData, price: Number(e.target.value)})} placeholder="Harga" />
                    <input type="number" className="input w-full" value={formData.discountPrice} onChange={e => setFormData({...formData, discountPrice: Number(e.target.value)})} placeholder="Harga Diskon (Opsional)" />
                    <select className="input w-full" value={formData.level} onChange={e => setFormData({...formData, level: e.target.value as any})}>
                       <option value="Starter">Starter</option>
                       <option value="Accelerator">Accelerator</option>
                       <option value="Mastery">Mastery</option>
                    </select>
                    <div className="flex gap-4">
                       <label className="flex items-center gap-2 text-white text-sm"><input type="checkbox" checked={formData.isPublished} onChange={e => setFormData({...formData, isPublished: e.target.checked})} /> Published</label>
                       <label className="flex items-center gap-2 text-white text-sm"><input type="checkbox" checked={formData.isFeatured} onChange={e => setFormData({...formData, isFeatured: e.target.checked})} /> Featured</label>
                    </div>
                 </div>
              </div>
           </div>

           {/* Thumbnail Card */}
           <div className="card p-8 space-y-6">
              <h2 className="text-lg font-bold text-white">Thumbnail</h2>
              <div className="flex gap-4">
                 <input className="input w-full" value={formData.thumbnail} onChange={e => setFormData({...formData, thumbnail: e.target.value})} placeholder="Thumbnail URL" />
                 <label className="btn-secondary !w-12 !p-0 flex items-center justify-center cursor-pointer">
                    {isUploading ? <Loader2 className="animate-spin" size={18} /> : <Upload size={18} />}
                    <input type="file" className="hidden" onChange={handleThumbnailUpload} />
                 </label>
              </div>
              {formData.thumbnail && <img src={formData.thumbnail} className="w-full h-48 object-cover rounded-xl border border-white/10" />}
           </div>

           {/* Description Card */}
           <div className="card p-8 space-y-6">
              <h2 className="text-lg font-bold text-white">Konten Deskripsi</h2>
              <textarea className="input w-full h-24" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} placeholder="Deskripsi Singkat" />
              <textarea className="input w-full h-48 font-mono text-sm" value={formData.detailedDescription} onChange={e => setFormData({...formData, detailedDescription: e.target.value})} placeholder="Deskripsi Detail (Markdown)" />
           </div>
        </div>
      )}

      {activeTab === "curriculum" && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
           <div className="card p-8 space-y-6">
              <div className="flex items-center justify-between border-b border-white/5 pb-4">
                 <h2 className="text-xl font-bold text-white flex items-center gap-2"><Play size={20} className="text-purple-400" /> Materi Kursus</h2>
                 <button type="button" onClick={() => openLessonModal()} disabled={!courseId} className="btn-primary !py-2 !px-4 text-xs">Tambah Materi</button>
              </div>
              <div className="space-y-4">
                 {formData.lessons.map((lesson, i) => (
                    <div key={lesson.id} className="p-4 rounded-xl bg-white/5 border border-white/10 flex items-center justify-between group">
                       <div className="flex items-center gap-4">
                          <div className="flex flex-col">
                             <button type="button" onClick={() => handleMoveLesson(i, 'up')} disabled={i === 0}><ChevronUp size={14} /></button>
                             <button type="button" onClick={() => handleMoveLesson(i, 'down')} disabled={i === formData.lessons.length - 1}><ChevronDown size={14} /></button>
                          </div>
                          <div>
                             <h4 className="text-white font-bold text-sm">{lesson.title}</h4>
                             <p className="text-[10px] text-slate-500 uppercase font-bold">{lesson.duration_minutes}m ΓÇó {lesson.content_type}</p>
                          </div>
                       </div>
                       <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button type="button" onClick={() => openLessonModal(lesson)} className="p-2 hover:bg-white/10 rounded-lg"><Edit size={16} /></button>
                          <button type="button" onClick={() => handleDeleteLesson(lesson.id, lesson.title)} className="p-2 hover:bg-red-500/10 text-red-400 rounded-lg"><Trash2 size={16} /></button>
                       </div>
                    </div>
                 ))}
                 {!courseId && <p className="text-center text-slate-500 italic text-sm">Simpan kursus terlebih dahulu.</p>}
              </div>
           </div>
        </div>
      )}

      {activeTab === "assessments" && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
           {!courseId ? (
              <p className="text-center text-slate-500 italic py-20">Simpan kursus terlebih dahulu untuk menambah asesmen.</p>
           ) : (
              <div className="grid md:grid-cols-2 gap-6">
                 {/* Quizzes */}
                 <div className="card p-8 space-y-6">
                    <div className="flex items-center justify-between border-b border-white/5 pb-4">
                       <h3 className="text-lg font-bold text-white flex items-center gap-2"><Brain size={18} className="text-purple-400" /> Kuis</h3>
                       <button type="button" onClick={() => setAssessmentModal({ isOpen: true, type: 'quiz', data: null, isSaving: false })} className="text-xs text-purple-400">+ Tambah</button>
                    </div>
                    {assessments.quizzes.map((q: any) => (
                       <div key={q.id} className="p-4 rounded-xl bg-white/5 border border-white/10 group">
                          <div className="flex justify-between items-center mb-2">
                             <span className="text-white font-bold text-sm">{q.title}</span>
                             <div className="flex gap-2">
                                <button type="button" onClick={() => setAssessmentModal({ isOpen: true, type: 'quiz', data: q, isSaving: false })}><Edit size={14} /></button>
                                <button type="button" onClick={() => handleDeleteAssessment(q.id, q.title)}><Trash2 size={14} /></button>
                             </div>
                          </div>
                          <button onClick={() => setQuestionModal({ isOpen: true, assessmentId: q.id, data: null, isSaving: false })} className="text-[10px] text-purple-400 font-bold tracking-widest uppercase">+ Add Question</button>
                       </div>
                    ))}
                 </div>

                 {/* Assignments */}
                 <div className="card p-8 space-y-6">
                    <div className="flex items-center justify-between border-b border-white/5 pb-4">
                       <h3 className="text-lg font-bold text-white flex items-center gap-2"><FileText size={18} className="text-cyan-400" /> Tugas</h3>
                       <button type="button" onClick={() => setAssessmentModal({ isOpen: true, type: 'assignment', data: null, isSaving: false })} className="text-xs text-cyan-400">+ Tambah</button>
                    </div>
                    {assessments.assignments.map((a: any) => (
                       <div key={a.id} className="p-4 rounded-xl bg-white/5 border border-white/10 group flex justify-between">
                          <span className="text-white font-bold text-sm">{a.title}</span>
                          <div className="flex gap-2">
                             <button type="button" onClick={() => setAssessmentModal({ isOpen: true, type: 'assignment', data: a, isSaving: false })}><Edit size={14} /></button>
                             <button type="button" onClick={() => handleDeleteAssessment(a.id, a.title)}><Trash2 size={14} /></button>
                          </div>
                       </div>
                    ))}
                 </div>
              </div>
           )}
        </div>
      )}

      {/* Lesson Modal */}
      {lessonModal.isOpen && (
         <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md">
            <div className="relative w-full max-w-lg bg-[#0F172A] border border-white/10 rounded-3xl p-8 space-y-4">
               <h3 className="text-xl font-bold text-white">Detail Materi</h3>
               <input className="input w-full" value={lessonModal.lesson?.title || ""} onChange={e => setLessonModal({...lessonModal, lesson: {...lessonModal.lesson, title: e.target.value}})} placeholder="Judul Materi" />
               <input type="number" className="input w-full" value={lessonModal.lesson?.duration_minutes || 0} onChange={e => setLessonModal({...lessonModal, lesson: {...lessonModal.lesson, duration_minutes: Number(e.target.value)}})} placeholder="Durasi (Menit)" />
               <VideoInput 
                 value={lessonModal.lesson?.video_url || ""} 
                 onChange={(url) => setLessonModal({...lessonModal, lesson: {...lessonModal.lesson, video_url: url}})}
                 label="Video Materi"
                 placeholder="Link YouTube atau URL Video"
               />
               <textarea className="input w-full h-24" value={lessonModal.lesson?.description || ""} onChange={e => setLessonModal({...lessonModal, lesson: {...lessonModal.lesson, description: e.target.value}})} placeholder="Deskripsi materi" />
               <div className="flex justify-end gap-3 mt-4">
                  <button type="button" onClick={() => setLessonModal({...lessonModal, isOpen: false})} className="btn-secondary">Batal</button>
                  <button type="button" onClick={() => handleSaveLesson(lessonModal.lesson)} className="btn-primary">Simpan</button>
               </div>
            </div>
         </div>
      )}

      {/* Assessment Modal */}
      {assessmentModal.isOpen && (
         <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md">
            <div className="relative w-full max-w-lg bg-[#0F172A] border border-white/10 rounded-3xl p-8 space-y-4">
               <h3 className="text-xl font-bold text-white font-bold">{assessmentModal.data?.id ? 'Edit' : 'Tambah'} {assessmentModal.type}</h3>
               <input className="input w-full" defaultValue={assessmentModal.data?.title} onChange={e => assessmentModal.data = {...assessmentModal.data, title: e.target.value}} placeholder="Judul" />
               <textarea className="input w-full h-24" defaultValue={assessmentModal.data?.description} onChange={e => assessmentModal.data = {...assessmentModal.data, description: e.target.value}} placeholder="Deskripsi" />
               <div className="flex justify-end gap-3">
                  <button type="button" onClick={() => setAssessmentModal({...assessmentModal, isOpen: false})} className="btn-secondary">Batal</button>
                  <button type="button" onClick={() => handleSaveAssessment({...assessmentModal.data, assessment_type: assessmentModal.type})} className="btn-primary">Simpan</button>
               </div>
            </div>
         </div>
      )}

      {/* Question Modal */}
      {questionModal.isOpen && (
         <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md">
            <div className="relative w-full max-w-xl bg-[#0F172A] border border-white/10 rounded-3xl p-8 space-y-4">
               <h3 className="text-xl font-bold text-white">Pertanyaan Kuis</h3>
               <textarea className="input w-full h-20" defaultValue={questionModal.data?.question_text} onChange={e => questionModal.data = {...questionModal.data, question_text: e.target.value}} placeholder="Teks Pertanyaan" />
               <div className="space-y-2">
                  {[0,1,2,3].map(i => (
                     <div key={i} className="flex gap-2">
                        <input type="radio" name="ans" checked={Number(questionModal.data?.correct_answer_index) === i} onChange={() => questionModal.data = {...questionModal.data, correct_answer_index: i}} />
                        <input className="input w-full py-1 text-xs" placeholder={`Opsi ${i+1}`} defaultValue={questionModal.data?.options?.[i]} onChange={e => {
                           const opts = [...(questionModal.data?.options || ['', '', '', ''])];
                           opts[i] = e.target.value;
                           questionModal.data = {...questionModal.data, options: opts};
                        }} />
                     </div>
                  ))}
               </div>
               <div className="flex justify-end gap-3 mt-4">
                  <button type="button" onClick={() => setQuestionModal({...questionModal, isOpen: false})} className="btn-secondary">Batal</button>
                  <button type="button" onClick={() => handleSaveQuestion({...questionModal.data, assessment_id: questionModal.assessmentId})} className="btn-primary">Simpan</button>
               </div>
            </div>
         </div>
      )}
    </form>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/app/components/AuthContext";
import { Enrollment, enrollCourse, getActiveEnrollment, getUserEnrollments } from "@/lib/enrollment";
import { getCourseAssessments } from "@/lib/assessments";
import { ArrowRight, AlertCircle, CheckCircle, LogIn, Clock, CreditCard } from "lucide-react";
import Link from "next/link";
import PaymentModal from "@/app/components/PaymentModal";

interface Props {
  courseId: string | number;
  courseSlug: string;
  courseTitle: string;
  totalLessons: number;
  level: string;
  price: number;
  instructorId: string;
  instructorQrisUrl?: string;
}

export default function CourseEnrollButton({ 
  courseId, courseSlug, courseTitle, totalLessons, level, price, instructorId, instructorQrisUrl 
}: Props) {
  const { user, isLoggedIn } = useAuth();
  const router = useRouter();
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [activeEnr, setActiveEnr] = useState<Enrollment | null>(null);
  const [enrollments, setEnrollments] = useState<Enrollment[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchEnrollments = async () => {
      if (!user) {
        setLoading(false);
        return;
      }
      const data = await getUserEnrollments(user.id);
      setEnrollments(data);
      setLoading(false);
    };
    fetchEnrollments();
  }, [user]);

  const currentEnr = enrollments.find(e => e.courseSlug === courseSlug);
  const anyActive = enrollments.find(e => e.status === "active");

  const isFree = price === 0;
  // Instructor info is now passed via props from the dynamic course data

  if (!isLoggedIn) {
    return (
      <div className="space-y-3">
        <Link href="/login" className="btn-primary w-full !py-3.5 text-base flex items-center justify-center gap-2">
          <LogIn size={18} /> Masuk untuk Mendaftar
        </Link>
        <Link href="/register" className="btn-secondary w-full !py-3 text-sm text-center block">
          Belum punya akun? Daftar
        </Link>
      </div>
    );
  }

  if (loading) {
    return <div className="btn-secondary w-full !py-3.5 animate-pulse">Menyiapkan...</div>;
  }

  if (currentEnr?.status === "active") {
    return (
      <Link href="/dashboard/my-courses" className="btn-primary w-full !py-3.5 text-base flex items-center justify-center gap-2">
        Lanjutkan Belajar <ArrowRight size={18} />
      </Link>
    );
  }

  if (currentEnr?.status === "waiting_verification") {
    return (
      <div className="card !bg-cyan-500/10 border-cyan-500/20 p-4 text-center">
        <Clock size={24} className="text-cyan-400 mx-auto mb-2" />
        <p className="text-white text-sm font-bold mb-1">Menunggu Verifikasi</p>
        <p className="text-slate-400 text-[10px]">Bukti pembayaran Anda sedang dicek oleh Admin.</p>
      </div>
    );
  }

  if (currentEnr?.status === "rejected" || currentEnr?.status === "pending") {
    return (
      <>
        {currentEnr.status === "rejected" && (
          <div className="mb-4 p-3 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-xs">
            <span className="font-bold block mb-1">Pembayaran Ditolak:</span>
            {currentEnr.rejectionReason}
          </div>
        )}
        <button
          onClick={() => setShowPaymentModal(true)}
          className="btn-primary w-full !py-3.5 text-base flex items-center justify-center gap-2"
        >
          <CreditCard size={18} /> {currentEnr.status === "rejected" ? "Upload Ulang Bukti" : "Bayar & Daftar"}
        </button>
        {showPaymentModal && (
          <PaymentModal 
            enrollment={currentEnr}
            courseTitle={courseTitle}
            qrisUrl={instructorQrisUrl || ""}
            onClose={() => setShowPaymentModal(false)}
            onSuccess={() => {
              setShowPaymentModal(false);
              setMessage({ type: "success", text: "Bukti berhasil dikirim! Menunggu verifikasi admin." });
            }}
          />
        )}
      </>
    );
  }

  const handleEnroll = async () => {
    if (!user) return;
    const assessments = await getCourseAssessments(courseSlug);
    const totalAssessmentItems = assessments ? assessments.quizzes.length + assessments.assignments.length + (assessments.finalProject ? 1 : 0) : 0;

    const result = await enrollCourse(user.id, courseSlug, courseTitle, totalLessons, level, totalAssessmentItems, isFree);

    if (result.success) {
      if (isFree) {
        setMessage({ type: "success", text: "Berhasil mendaftar! Mengarahkan ke kursus..." });
        setTimeout(() => router.push("/dashboard/my-courses"), 1500);
      } else {
        setActiveEnr(result.enrollment!);
        setShowPaymentModal(true);
      }
    } else {
      setMessage({ type: "error", text: result.error || "Gagal mendaftar." });
    }
  };

  return (
    <div className="space-y-3">
      {message && (
        <div className={`flex items-center gap-2 p-3 rounded-xl text-xs ${
          message.type === "success" ? "bg-emerald-500/10 border border-emerald-500/20 text-emerald-400" : "bg-red-500/10 border border-red-500/20 text-red-400"
        }`}>
          {message.type === "success" ? <CheckCircle size={14} /> : <AlertCircle size={14} />}
          {message.text}
        </div>
      )}
      <button
        onClick={handleEnroll}
        disabled={!!anyActive}
        className={`w-full !py-3.5 text-base flex items-center justify-center gap-2 ${anyActive ? "btn-secondary opacity-50 cursor-not-allowed" : "btn-primary"}`}
      >
        {anyActive ? (
          <>Selesaikan Kursus Aktif Dulu</>
        ) : (
          <>{isFree ? "Daftar Gratis Sekarang" : "Beli Kursus Sekarang"}</>
        )}
      </button>

      {anyActive && (
        <p className="text-xs text-amber-400 text-center">
          Kursus aktif anda: {anyActive.courseTitle}
        </p>
      )}

      {showPaymentModal && activeEnr && (
        <PaymentModal 
          enrollment={activeEnr}
          courseTitle={courseTitle}
          qrisUrl={instructorQrisUrl || ""}
          onClose={() => {
            setShowPaymentModal(false);
            window.location.reload(); // Reload to show waiting status
          }}
          onSuccess={() => {
            setShowPaymentModal(false);
            setMessage({ type: "success", text: "Bukti berhasil dikirim! Menunggu verifikasi admin." });
            window.location.reload();
          }}
        />
      )}
    </div>
  );
}

