            if (confirm("Hapus SEMUA data? Ini akan menghapus semua user, enrollment, dan pesan. Tidak bisa dibatalkan!")) {
              localStorage.clear();
              window.location.reload();
            }
          }}
          className="px-4 py-2 rounded-lg bg-red-500/10 border border-red-500/20 text-red-400 text-sm font-medium hover:bg-red-500/20 transition-colors"
        >
          Reset Semua Data
        </button>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { getAllRegisteredUsers, updateUserRole, deleteUser, type UserRole, type SafeUser } from "@/lib/auth";
import { getAllEnrollmentsAdmin, type Enrollment } from "@/lib/enrollment";
import { Users, Shield, Trash2, Search, AlertCircle } from "lucide-react";

export default function AdminUsersPage() {
  const [users, setUsers] = useState<SafeUser[]>([]);
  const [allEnrollments, setAllEnrollments] = useState<Enrollment[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [refresh, setRefresh] = useState(0);

  useEffect(() => {
    const fetchUsers = async () => {
      const data = await getAllRegisteredUsers();
      const enrollments = await getAllEnrollmentsAdmin();
      setUsers(data);
      setAllEnrollments(enrollments);
      setLoading(false);
    };
    fetchUsers();
  }, [refresh]);

  const filtered = search
    ? users.filter((u) => u.fullName.toLowerCase().includes(search.toLowerCase()) || u.email.toLowerCase().includes(search.toLowerCase()))
    : users;

  const handleRoleChange = async (userId: string, newRole: UserRole) => {
    const result = await updateUserRole(userId, newRole);
    if (!result.success) alert(result.error);
    setRefresh((r) => r + 1);
  };

  const handleDelete = async (userId: string, name: string) => {
    if (confirm(`Hapus user "${name}"? Tindakan ini tidak bisa dibatalkan.`)) {
      const result = await deleteUser(userId);
      if (!result.success) alert(result.error);
      setRefresh((r) => r + 1);
    }
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Loading users...</div>;

  return (
    <div className="max-w-5xl space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Kelola <span className="gradient-text">Pengguna</span></h1>
          <p className="text-slate-400 text-sm mt-1">{users.length} pengguna terdaftar</p>
        </div>
      </div>

      <div className="relative max-w-sm">
        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
        <input type="text" value={search} onChange={(e) => setSearch(e.target.value)} placeholder="Cari pengguna..." className="input !pl-9 !text-sm" />
      </div>

      <div className="card overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-white/5">
                <th className="text-left px-5 py-3 text-xs font-semibold text-slate-500 uppercase">Pengguna</th>
                <th className="text-left px-5 py-3 text-xs font-semibold text-slate-500 uppercase">Email</th>
                <th className="text-left px-5 py-3 text-xs font-semibold text-slate-500 uppercase">Role</th>
                <th className="text-left px-5 py-3 text-xs font-semibold text-slate-500 uppercase">Kursus</th>
                <th className="text-left px-5 py-3 text-xs font-semibold text-slate-500 uppercase">Bergabung</th>
                <th className="text-right px-5 py-3 text-xs font-semibold text-slate-500 uppercase">Aksi</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((u) => {
                const enrollmentCount = allEnrollments.filter(e => e.userId === u.id).length;
                return (
                  <tr key={u.id} className="border-b border-white/5 last:border-0 hover:bg-white/[0.02]">
                    <td className="px-5 py-3">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-br from-purple-500 to-cyan-400 flex items-center justify-center text-white text-xs font-bold">
                          {u.fullName.split(" ").map((n) => n[0]).join("").substring(0, 2)}
                        </div>
                        <span className="text-white font-medium">{u.fullName}</span>
                      </div>
                    </td>
                    <td className="px-5 py-3 text-slate-400 text-xs font-family-mono">{u.email}</td>
                    <td className="px-5 py-3">
                      <select
                        value={u.role}
                        onChange={(e) => handleRoleChange(u.id, e.target.value as UserRole)}
                        className="bg-white/5 border border-white/10 rounded-lg text-xs px-2 py-1 text-slate-300 outline-none"
                        disabled={u.email === "admin@mylearning.id"}
                      >
                        <option value="user">User</option>
                        <option value="admin">Admin</option>
                      </select>
                    </td>
                    <td className="px-5 py-3 text-slate-400">{enrollmentCount}</td>
                    <td className="px-5 py-3 text-slate-500 text-xs">{new Date(u.createdAt).toLocaleDateString("id-ID")}</td>
                    <td className="px-5 py-3 text-right">
                      {u.email !== "admin@mylearning.id" && (
                        <button onClick={() => handleDelete(u.id, u.fullName)} className="text-red-400/60 hover:text-red-400 transition-colors">
                          <Trash2 size={16} />
                        </button>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useMemo, useEffect } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useAuth } from "@/app/components/AuthContext";
import { type Course, type Category } from "@/lib/data";
import { formatPrice, formatNumber } from "@/lib/utils";
import { getCourses, getCategories } from "@/lib/courses";
import { getLevelLabel, getLevelBg, enrollCourse, getActiveEnrollment, getExpiryDays } from "@/lib/enrollment";
import { Star, Users, Clock, BookOpen, Search, X, AlertCircle, CheckCircle } from "lucide-react";

export default function DashboardCoursesPage() {
  const { user } = useAuth();
  const router = useRouter();
  const [search, setSearch] = useState("");
  const [category, setCategory] = useState("all");
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);
  const [activeEnrollment, setActiveEnrollment] = useState<any>(null);
  const [courses, setCourses] = useState<Course[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const [coursesData, categoriesData] = await Promise.all([
        getCourses(),
        getCategories()
      ]);
      setCourses(coursesData);
      setCategories([{ name: "Semua", slug: "all", icon: "≡ƒôÜ", courseCount: 0 }, ...categoriesData]);

      if (user) {
        getActiveEnrollment(user.id).then(setActiveEnrollment);
      }
      setLoading(false);
    };
    fetchData();
  }, [user]);

  const filtered = useMemo(() => {
    let result = courses.filter((c) => c.isPublished);
    if (category !== "all") result = result.filter((c) => c.categorySlug === category);
    if (search) {
      const q = search.toLowerCase();
      result = result.filter((c) => c.title.toLowerCase().includes(q) || c.instructor.toLowerCase().includes(q));
    }
    return result;
  }, [search, category, courses]);

  const handleEnroll = async (course: typeof courses[0]) => {
    if (!user) return;
    const result = await enrollCourse(user.id, course.slug, course.title, course.totalLessons, course.level);
    if (result.success) {
      setMessage({ type: "success", text: `Berhasil mendaftar ke "${course.title}"!` });
      setTimeout(() => router.push("/dashboard/my-courses"), 1500);
    } else {
      setMessage({ type: "error", text: result.error || "Gagal mendaftar." });
    }
  };

  return (
    <div className="max-w-6xl space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-white">Jelajahi <span className="gradient-text">Kursus</span></h1>
        <p className="text-slate-400 text-sm mt-1">Pilih kursus untuk memulai perjalanan belajar Anda</p>
      </div>

      {message && (
        <div className={`flex items-center gap-2 p-3 rounded-xl text-sm ${
          message.type === "success" ? "bg-emerald-500/10 border border-emerald-500/20 text-emerald-400" : "bg-red-500/10 border border-red-500/20 text-red-400"
        }`}>
          {message.type === "success" ? <CheckCircle size={16} /> : <AlertCircle size={16} />}
          {message.text}
        </div>
      )}

      {activeEnrollment && (
        <div className="flex items-center gap-2 p-3 rounded-xl bg-amber-500/10 border border-amber-500/20 text-amber-400 text-sm">
          <AlertCircle size={16} className="flex-shrink-0" />
          Anda sudah memiliki kursus aktif: <strong>{activeEnrollment.courseTitle}</strong>. Selesaikan terlebih dahulu.
        </div>
      )}

      {/* Search + Filters */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-500" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Cari kursus..."
            className="input !pl-11 !pr-10"
          />
          {search && (
            <button onClick={() => setSearch("")} className="absolute right-3.5 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white">
              <X size={16} />
            </button>
          )}
        </div>
      </div>

      <div className="flex flex-wrap gap-2">
        {categories.map((cat) => (
          <button
            key={cat.slug}
            onClick={() => setCategory(cat.slug)}
            className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
              category === cat.slug
                ? "bg-gradient-to-r from-purple-600 to-cyan-500 text-white"
                : "bg-white/5 text-slate-400 hover:text-white hover:bg-white/10"
            }`}
          >
            {cat.icon} {cat.name}
          </button>
        ))}
      </div>

      {/* Course Grid */}
      {loading ? (
        <div className="p-12 text-center text-slate-500">Memuat katalog kursus...</div>
      ) : (
        <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-5">
          {filtered.map((course) => (
            <div key={course.id} className="card overflow-hidden group">
              <div className="relative h-36 bg-gradient-to-br from-purple-900/40 to-cyan-900/30 flex items-center justify-center">
                <BookOpen size={32} className="text-purple-400/40" />
                <span className="absolute top-2 left-2 badge badge-primary text-xs">{course.category}</span>
                <span className={`absolute top-2 right-2 text-xs px-2 py-0.5 rounded-full border ${getLevelBg(course.level)}`}>
                  {getLevelLabel(course.level)}
                </span>
              </div>
              <div className="p-4 space-y-3">
                <h3 className="text-white font-semibold text-sm leading-snug line-clamp-2">{course.title}</h3>
                <p className="text-slate-500 text-xs">{course.instructor}</p>
                <div className="flex items-center gap-3 text-xs text-slate-400">
                  <span className="flex items-center gap-1"><Star size={12} className="text-yellow-400 fill-yellow-400" /> {course.rating}</span>
                  <span>({formatNumber(course.totalReviews)})</span>
                  <span className="flex items-center gap-1"><Users size={12} /> {formatNumber(course.totalStudents)}</span>
                </div>
                <div className="flex items-center gap-2 text-xs text-slate-500">
                  <Clock size={12} /> {course.durationHours}j ΓÇó {course.totalLessons} pelajaran ΓÇó {getExpiryDays(course.level)} hari deadline
                </div>
                <div className="flex items-center justify-between pt-2 border-t border-white/5">
                  <div className="flex items-center gap-2">
                    {course.discountPrice ? (
                      <>
                        <span className="text-white font-bold text-sm">{formatPrice(course.discountPrice)}</span>
                        <span className="text-slate-500 text-xs line-through">{formatPrice(course.price)}</span>
                      </>
                    ) : (
                      <span className="text-white font-bold text-sm">{formatPrice(course.price)}</span>
                    )}
                  </div>
                  <button
                    onClick={() => handleEnroll(course)}
                    disabled={!!activeEnrollment}
                    className={`text-xs px-3 py-1.5 rounded-lg font-medium transition-all ${
                      activeEnrollment
                        ? "bg-white/5 text-slate-600 cursor-not-allowed"
                        : "bg-purple-500/20 text-purple-300 hover:bg-purple-500/30"
                    }`}
                  >
                    Ambil Kursus
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {filtered.length === 0 && (
        <div className="text-center py-12">
          <BookOpen size={40} className="text-slate-600 mx-auto mb-3" />
          <p className="text-white font-semibold">Tidak ada kursus ditemukan</p>
          <p className="text-slate-500 text-sm">Coba ubah filter pencarian</p>
        </div>
      )}
    </div>
  );
}

