export async function getAllRegisteredUsers(): Promise<SafeUser[]> {
  try {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return [];

    const { data: profile } = await supabase
      .from("user_profiles")
      .select("role")
      .eq("user_id", user.id)
      .single();

    if (profile?.role !== "admin") return [];

    const { data: profiles, error } = await supabase
      .from("user_profiles")
      .select("*");

    if (error || !profiles) return [];

    return profiles.map(p => ({
      id: p.user_id,
      email: "user@hidden.com", // Hidden for privacy/admin logic
      fullName: p.full_name,
      phone: p.phone || "",
      bio: p.bio || "",
      role: p.role as UserRole,
      createdAt: p.created_at,
      avatarUrl: p.avatar_url,
    }));
  } catch (error) {
    console.error(error);
    return [];
  }
}

export async function updateUserRole(userId: string, newRole: UserRole): Promise<{ success: boolean; error?: string }> {
  try {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error("Unauthorized");

    const { data: profile } = await supabase
      .from("user_profiles")
      .select("role")
      .eq("user_id", user.id)
      .single();

    if (profile?.role !== "admin") throw new Error("Forbidden: Admin only");

    const { error } = await supabase
      .from("user_profiles")
      .update({ role: newRole })
      .eq("user_id", userId);

    if (error) throw error;
    return { success: true };
  } catch (error: any) {
    return { success: false, error: error.message };
  }
}

export async function deleteUser(userId: string): Promise<{ success: boolean; error?: string }> {
  try {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error("Unauthorized");

    const { data: profile } = await supabase
      .from("user_profiles")
      .select("role")
      .eq("user_id", user.id)
      .single();

    if (profile?.role !== "admin") throw new Error("Forbidden: Admin only");

    const { error } = await supabase
      .from("user_profiles")
      .delete()
      .eq("user_id", userId);

    if (error) throw error;
    return { success: true };
  } catch (error: any) {
    return { success: false, error: error.message };
  }
